/**
 * Bain Design — main.min.js
 * Interaction layer: hero animation, menu toggle, portfolio tilt, quirks.
 * Vanilla JS, no dependencies.
 */
(function () {
	'use strict';

	const rand = n => Math.floor(Math.random() * n);

	if (document.readyState === 'loading') {
		document.addEventListener('DOMContentLoaded', init);
	} else {
		init();
	}

	function init() {
		initMenuToggle();
		initBrandMark();
		initTip();
		initNavTips();
		initHero();
		initPortfolioCards();
		initFooter();
		initEmailCopy();
		initToast();
		initCursorTrail();
		initTypeTriggers();
		initConsoleBanner();
		initPet();
	}

	/* ------------------------------------------------------------------ Menu */

	function initMenuToggle() {
		const toggle = document.getElementById('menu-toggle');
		const nav    = document.getElementById('primary-nav');
		if (!toggle || !nav) return;
		toggle.addEventListener('click', () => {
			const open = nav.classList.toggle('is-open');
			toggle.setAttribute('aria-expanded', String(open));
			toggle.textContent = open ? '[close]' : '[menu]';
		});
	}

	/* --------------------------------------------------------------- Bd mark */

	function initBrandMark() {
		const mark = document.getElementById('bd-mark');
		if (!mark) return;
		const MARKS = ['Bd', 'B|', 'B_', 'B/'];
		let idx     = parseInt(localStorage.getItem('bd-mark-idx'), 10) || 0;
		let toasted = false;
		mark.textContent = MARKS[idx];
		mark.addEventListener('click', e => {
			e.preventDefault();
			e.stopPropagation();
			idx = (idx + 1) % MARKS.length;
			mark.textContent = MARKS[idx];
			localStorage.setItem('bd-mark-idx', idx);
			mark.classList.add('is-bouncing');
			setTimeout(() => mark.classList.remove('is-bouncing'), 400);
			if (!toasted) { bdToast('hello, you found it'); toasted = true; }
		});
	}

	/* ---------------------------------------------------------- Tip tooltips */

	function initTip() {
		const tip = document.createElement('div');
		tip.id = 'bd-tip';
		tip.setAttribute('aria-hidden', 'true');
		tip.style.cssText =
			'position:fixed;z-index:9999;pointer-events:none;' +
			'background:var(--ink);color:var(--paper);' +
			'font-family:var(--font-mono-2);font-size:11px;line-height:1.3;' +
			'padding:6px 8px;white-space:nowrap;box-shadow:2px 2px 0 var(--clay);' +
			'opacity:0;transition:opacity 80ms;';
		document.body.appendChild(tip);

		let showTimer;

		document.addEventListener('mousemove', e => {
			const above = e.clientY - 36;
			tip.style.left = (e.clientX + 14) + 'px';
			tip.style.top  = (above > 4 ? above : e.clientY + 18) + 'px';
		});

		document.addEventListener('mouseover', e => {
			const target = e.target.closest('[data-tip]');
			if (!target) return;
			clearTimeout(showTimer);
			const rot = (Math.random() - 0.5) * 3;
			tip.innerHTML = '<span style="color:var(--clay)">$ </span>' + target.dataset.tip;
			tip.style.transform = 'rotate(' + rot + 'deg)';
			showTimer = setTimeout(() => { tip.style.opacity = '1'; }, 120);
		});

		document.addEventListener('mouseout', e => {
			const target = e.target.closest('[data-tip]');
			if (!target || target.contains(e.relatedTarget)) return;
			clearTimeout(showTimer);
			tip.style.opacity = '0';
		});
	}

	function initNavTips() {
		const NAV_TIPS = {
			'home':             'pwd → /',
			'about':            'whoami',
			'about mark bain':  'whoami',
			'services':         'ls services/',
			'work':             'cat portfolio.md',
			'portfolio':        'cat portfolio.md',
			'nice words':       'grep -i kind reviews/*',
			'contact':          'open mailto:hello',
		};
		document.querySelectorAll('#primary-nav a').forEach(a => {
			const key = a.textContent.trim().toLowerCase();
			if (NAV_TIPS[key]) a.dataset.tip = NAV_TIPS[key];
		});
	}

	/* ------------------------------------------------------------------ Hero */

	function initHero() {
		const headline = document.getElementById('hero-headline');
		const caretEl  = document.getElementById('hero-caret');
		if (!headline || !caretEl) return;

		const WORDS = [
			['Friendly', 'Stunning', 'Quirky', 'Fun', 'Honest', 'Bespoke', 'Tasteful'],
			['interesting', 'creative', 'artistic', 'curious', 'thoughtful', 'ambitious'],
			['people', 'artists', 'writers', 'entrepreneurs', 'start-ups', 'businesses', 'firms', 'founders'],
		];

		const NBRS = {
			a:'sq', b:'vn', c:'xv', d:'sf', e:'wr', f:'dg', g:'fh', h:'gj', i:'uo', j:'hk',
			k:'jl', l:'k',  m:'n',  n:'mb', o:'ip', p:'o',  q:'wa', r:'et', s:'ad', t:'ry',
			u:'yi', v:'cb', w:'qe', x:'zc', y:'tu', z:'x',
		};

		function typoChar(c) {
			const ns = NBRS[c.toLowerCase()];
			if (!ns) return c;
			const t = ns[rand(ns.length)];
			return c === c.toLowerCase() ? t : t.toUpperCase();
		}

		const textEls = [0, 1, 2].map(i => document.getElementById('slot-' + i + '-text'));

		const texts   = WORDS.map(w => w[0]);  // live displayed text
		const indices = [0, 0, 0];             // current word index per slot

		let active = 0;
		let phase  = 'hold'; // 'hold' | 'editing' | 'transit'
		let timer  = null;
		let plan   = null;   // { steps, ptr, doneEdits, reEdits, lastIdx, finalIdx }

		/* Measure the caret position (end of text when atEnd=true, start when false) */
		function measurePos(slotIdx, atEnd) {
			const el = textEls[slotIdx];
			const hostRect = headline.getBoundingClientRect();
			const txt = el.firstChild;
			if (txt && txt.nodeType === 3 && txt.length > 0) {
				const range = document.createRange();
				if (atEnd) {
					range.setStart(txt, txt.length - 1);
					range.setEnd(txt, txt.length);
				} else {
					range.setStart(txt, 0);
					range.setEnd(txt, 1);
				}
				const rects = range.getClientRects();
				const r = atEnd ? rects[rects.length - 1] : rects[0];
				if (r) return {
					left:   atEnd ? r.right - hostRect.left : r.left - hostRect.left,
					top:    r.top - hostRect.top,
					height: r.height,
				};
			}
			// Fallback: use the slot container
			const slot = el.closest('.hero__slot') || el;
			const r = slot.getBoundingClientRect();
			const h = parseFloat(getComputedStyle(headline).fontSize) * 1.25;
			return { left: r.left - hostRect.left, top: r.top - hostRect.top, height: h };
		}

		function placeCaret(pos, blinking) {
			caretEl.style.transform = 'translate(' + pos.left + 'px,' + pos.top + 'px)';
			caretEl.style.height    = (pos.height || 48) + 'px';
			caretEl.style.opacity   = '1';
			caretEl.style.animation = blinking
				? 'bain-caret-blink 1.06s steps(2) infinite'
				: 'none';
		}

		function updateCaret() {
			placeCaret(measurePos(active, true), phase === 'hold');
		}

		function setSlotText(i, str) {
			texts[i] = str;
			textEls[i].textContent = str;
			if (i === active) updateCaret();
		}

		/* Build an edit plan: delete current word, optionally false-start, type new word */
		function buildPlan(slotIdx) {
			const curText  = texts[slotIdx];
			const allWords = WORDS[slotIdx];
			const curIdx   = plan.lastIdx;
			const steps    = [];

			for (let i = 0; i < curText.length; i++) steps.push({ kind: 'del' });

			if (Math.random() < 0.3) {
				const otherIdx = (curIdx + 1 + rand(allWords.length - 1)) % allWords.length;
				const other    = allWords[otherIdx];
				const pfx      = 1 + rand(Math.min(other.length - 1, 4));
				for (let i = 0; i < pfx; i++) steps.push({ kind: 'type', ch: other[i] });
				steps.push({ kind: 'pause', ms: 220 });
				for (let i = 0; i < pfx; i++) steps.push({ kind: 'del' });
			}

			let nextIdx = curIdx;
			while (allWords.length > 1 && nextIdx === curIdx) nextIdx = rand(allWords.length);
			const target   = allWords[nextIdx];
			const willTypo = Math.random() < 0.45 && target.length >= 4;
			const typoAt   = willTypo ? 1 + rand(target.length - 2) : -1;

			for (let i = 0; i < target.length; i++) {
				if (i === typoAt) {
					steps.push({ kind: 'type', ch: typoChar(target[i]) });
					steps.push({ kind: 'pause', ms: 200 });
					steps.push({ kind: 'del' });
				}
				steps.push({ kind: 'type', ch: target[i] });
			}

			return { steps, nextIdx };
		}

		function tick() {
			clearTimeout(timer);

			if (phase === 'hold') {
				timer = setTimeout(() => {
					const r = Math.random();
					plan = {
						reEdits: r < 0.65 ? 1 : r < 0.92 ? 2 : 3,
						doneEdits: 0, steps: [], ptr: 0,
						lastIdx: indices[active], finalIdx: indices[active],
					};
					phase = 'editing';
					tick();
				}, 900 + rand(600));
				return;
			}

			if (phase === 'editing') {
				if (plan.ptr >= plan.steps.length) {
					if (plan.doneEdits >= plan.reEdits) {
						indices[active] = plan.finalIdx;
						timer = setTimeout(() => { phase = 'transit'; doTransit(); }, 600 + rand(500));
						return;
					}
					const sub = buildPlan(active);
					plan.steps     = sub.steps;
					plan.ptr       = 0;
					plan.lastIdx   = sub.nextIdx;
					plan.finalIdx  = sub.nextIdx;
					plan.doneEdits++;
				}

				const step = plan.steps[plan.ptr];
				const dur  = step.kind === 'pause' ? step.ms
				           : step.kind === 'del'   ? 32 + rand(28)
				           :                        50 + rand(85);

				timer = setTimeout(() => {
					if      (step.kind === 'type') setSlotText(active, texts[active] + step.ch);
					else if (step.kind === 'del')  setSlotText(active, texts[active].slice(0, -1));
					plan.ptr++;
					tick();
				}, dur);
			}
		}

		/* Move caret line-by-line from current slot end to next slot start */
		function doTransit() {
			const nextActive = (active + 1) % WORDS.length;
			const lineH      = parseFloat(getComputedStyle(headline).lineHeight)
			                || 1.25 * parseFloat(getComputedStyle(headline).fontSize);

			const fromPos = measurePos(active, true);
			const toPos   = measurePos(nextActive, false);

			const fromLine = Math.round(fromPos.top / lineH);
			const toLine   = Math.round(toPos.top / lineH);
			const steps    = [];

			if (fromLine !== toLine) {
				const dir = fromLine < toLine ? 1 : -1;
				for (let ln = fromLine + dir; ln !== toLine; ln += dir) {
					steps.push({ left: 0, top: ln * lineH, height: fromPos.height });
				}
			}
			steps.push(toPos);

			const STEP_MS = 280;
			let i = 0;
			function advance() {
				if (i >= steps.length) {
					active = nextActive;
					phase  = 'hold';
					updateCaret();
					tick();
					return;
				}
				placeCaret(steps[i], false);
				i++;
				setTimeout(advance, STEP_MS);
			}
			setTimeout(advance, STEP_MS);
		}

		/* Boot */
		function onFontsReady() { updateCaret(); }
		if (document.fonts && document.fonts.ready) document.fonts.ready.then(onFontsReady);
		window.addEventListener('resize', () => { if (phase === 'hold') updateCaret(); });

		placeCaret({ left: 0, top: 0, height: parseFloat(getComputedStyle(headline).fontSize) * 1.25 }, true);
		tick();
	}

	/* ---------------------------------------------------- Portfolio card tilt */

	function initPortfolioCards() {
		document.querySelectorAll('.portfolio-card').forEach(card => {
			card.addEventListener('mousemove', e => {
				const r  = card.getBoundingClientRect();
				const cx = (e.clientX - r.left) / r.width  - 0.5;
				const cy = (e.clientY - r.top)  / r.height - 0.5;
				card.style.transform = `perspective(800px) rotateX(${-cy * 5}deg) rotateY(${cx * 5}deg) translateZ(0)`;
				card.style.boxShadow = '6px 6px 0 var(--clay)';
			});
			card.addEventListener('mouseleave', () => {
				card.style.transform = '';
				card.style.boxShadow = '';
			});
		});
	}

	/* --------------------------------------------------------------- Footer */

	function initFooter() {
		const verbEl = document.getElementById('footer-verb');
		if (verbEl) {
			const VERBS = ['Build', 'Built', 'Brewed', 'Bashed', 'Baked'];
			let idx = 0;
			verbEl.addEventListener('click', () => {
				idx = (idx + 1) % VERBS.length;
				verbEl.textContent = VERBS[idx];
			});
		}

		const heartEl = document.getElementById('footer-heart');
		if (heartEl) {
			heartEl.addEventListener('mouseenter', () => {
				heartEl.style.animation = 'bd-heart 600ms ease-in-out infinite';
			});
			heartEl.addEventListener('mouseleave', () => {
				heartEl.style.animation = 'none';
			});
		}
	}

	/* ---------------------------------------------------------- Email copy */

	function initEmailCopy() {
		const link = document.getElementById('contact-email');
		if (!link) return;
		const orig = link.textContent;
		link.addEventListener('click', () => {
			if (!navigator.clipboard) return;
			navigator.clipboard.writeText('hello@bain.design').then(() => {
				link.textContent = '✓ copied — also opening →';
				bdToast('email copied — also opens your client');
				setTimeout(() => { link.textContent = orig; }, 1600);
			});
		});
	}

	/* ---------------------------------------------------------------- Toast */

	let toastContainer = null;

	function bdToast(msg) {
		if (!toastContainer) {
			toastContainer = document.createElement('div');
			toastContainer.style.cssText =
				'position:fixed;bottom:24px;right:24px;z-index:1000;display:flex;flex-direction:column;gap:8px;pointer-events:none;';
			document.body.appendChild(toastContainer);
		}
		const el = document.createElement('div');
		el.style.cssText =
			'background:var(--ink);color:var(--paper);font-family:var(--font-mono);font-size:13px;font-weight:600;' +
			'padding:10px 14px;box-shadow:4px 4px 0 var(--clay);animation:bd-toast-in 280ms cubic-bezier(.2,.9,.3,1.2);';
		el.innerHTML = '<span style="color:var(--clay);margin-right:6px">›</span>' + msg;
		toastContainer.appendChild(el);
		setTimeout(() => el.remove(), 2400);
	}

	function initToast() {
		// Inject keyframe if not already present
		if (!document.getElementById('bd-toast-kf')) {
			const s = document.createElement('style');
			s.id = 'bd-toast-kf';
			s.textContent = '@keyframes bd-toast-in{from{transform:translateY(20px);opacity:0}to{transform:none;opacity:1}}';
			document.head.appendChild(s);
		}
		// Expose globally for Contact JSX parity
		window.bdToast = bdToast;
	}

	/* --------------------------------------------------------- Cursor trail */

	function initCursorTrail() {
		let last = { x: 0, y: 0, t: 0 };
		window.addEventListener('mousemove', e => {
			const now = performance.now();
			const dx = e.clientX - last.x, dy = e.clientY - last.y;
			if (dx * dx + dy * dy < 1400 || now - last.t < 60) return;
			last = { x: e.clientX, y: e.clientY, t: now };
			const dot = document.createElement('div');
			dot.style.cssText =
				'position:fixed;left:' + (e.clientX - 3) + 'px;top:' + (e.clientY - 3) + 'px;' +
				'width:6px;height:6px;background:var(--clay);pointer-events:none;z-index:999;' +
				'opacity:0.7;transition:opacity 600ms ease,transform 600ms ease;';
			document.body.appendChild(dot);
			requestAnimationFrame(() => { dot.style.opacity = '0'; dot.style.transform = 'scale(0.3)'; });
			setTimeout(() => dot.remove(), 700);
		});
	}

	/* -------------------------------------------------------- Type triggers */

	function initTypeTriggers() {
		const TRIGGERS = {
			hello:   () => bdToast('hi back ✋'),
			hi:      () => bdToast('oh hey'),
			mark:    () => bdToast('that\'s me'),
			coffee:  () => bdToast('☕ refilled'),
			wow:     () => bdToast('thanks, I try'),
			why:     () => bdToast('why not?'),
			rosebud: () => document.body.classList.toggle('bd-invert'),
		};
		let buf = '';
		document.addEventListener('keydown', e => {
			const t = e.target;
			if (t && (t.tagName === 'INPUT' || t.tagName === 'TEXTAREA' || t.isContentEditable)) return;
			if (e.key.length === 1) {
				buf = (buf + e.key.toLowerCase()).slice(-24);
				for (const [kw, fn] of Object.entries(TRIGGERS)) {
					if (buf.endsWith(kw)) { fn(); buf = ''; return; }
				}
			}
		});
		// Invert style (for the rosebud trigger)
		const s = document.createElement('style');
		s.textContent = 'body.bd-invert{filter:invert(1) hue-rotate(180deg);transition:filter 400ms}';
		document.head.appendChild(s);
	}

	/* ----------------------------------------------------------------- Pet */

	function initPet() {
		const pets = document.querySelectorAll('.bain-pet');
		if (!pets.length) return;

		fetch('/wp-content/themes/bain-design-theme/assets/data/cats.json')
			.then(r => r.json())
			.then(catsData => {
				const CONFIGS = {
					Gala: {
						frames: catsData.gala.frames,
						speed: catsData.gala.speed,
						startLeft: catsData.gala.startLeft,
						msgs: catsData.gala.messages.pet,
					},
					Salvador: {
						frames: catsData.salvador.frames,
						speed: catsData.salvador.speed,
						startLeft: catsData.salvador.startLeft,
						msgs: catsData.salvador.messages.pet,
					},
				};
				pets.forEach(el => {
					const name = el.dataset.petname || 'Gala';
					const cfg  = CONFIGS[name] || CONFIGS.Gala;
					spawnPet(el, cfg);
				});
			})
			.catch(() => {
				// Fallback: inline defaults if JSON fails to load
				const CONFIGS = {
					Gala: {
						frames: {
							walkA: ' /\\_/\\\n(^.^)> ',
							walkB: ' /\\_/\\\n(^-^)> ',
							idle:  ' /\\_/\\\n (^.^) ',
							sleep: ' /\\_/\\\n(-.-) z',
							blink: ' /\\_/\\\n(O.O)! ',
							pet:   ' /\\_/\\\n(*^.^*) ',
						},
						speed:     58,
						startLeft: true,
						msgs: ['mrrp', 'purrr', 'ok fine', 'ok, enough', 'still here', '...', 'I said enough', 'you again'],
					},
					Salvador: {
						frames: {
							walkA: ' /\\_/\\\n(=.=)> ',
							walkB: ' /\\_/\\\n(-_-)> ',
							idle:  ' /\\_/\\\n (=.=) ',
							sleep: ' /\\_/\\\n(-.-) z',
							blink: ' /\\_/\\\n(O.o)! ',
							pet:   ' /\\_/\\\n(*=.=*) ',
						},
						speed:     42,
						startLeft: false,
						msgs: ['...', 'hmm.', 'if you insist', 'I suppose', 'fine.', 'enough now', 'I have things to do', 'you again'],
					},
				};
				pets.forEach(el => {
					const name = el.dataset.petname || 'Gala';
					const cfg  = CONFIGS[name] || CONFIGS.Gala;
					spawnPet(el, cfg);
				});
			});

		return;

		function spawnPet(el, cfg) {
			const sprite = el.querySelector('.bain-pet__sprite');
			const F      = cfg.frames;

			const SPEED       = cfg.speed;
			const FRAME_MS    = 380;
			const SLEEP_AFTER = 2000;

			const w0 = window.innerWidth;
			let x    = cfg.startLeft
			         ? 40  + rand(Math.floor(w0 * 0.3))
			         : Math.floor(w0 * 0.55) + rand(Math.floor(w0 * 0.3));

			let dir          = 1;
			let state        = 'sleep';
			let prevState    = 'sleep';
			let target       = x;
			let frame        = 0;
			let lastFlip     = 0;
			let lastScrollTs = 0;
			let lastTs       = null;
			let prevScrollY  = window.scrollY;
			let zInterval    = null;
			let zCount       = 0;
			let petCount     = 0;

			const maxX = () => Math.max(0, window.innerWidth - (el.offsetWidth || 72) - 8);
			const set  = key => { sprite.textContent = F[key]; };

			function spawnZ() {
				const rect = el.getBoundingClientRect();
				const z    = document.createElement('span');
				const big  = zCount % 3 === 2;
				z.textContent = big ? 'Z' : 'z';
				z.style.cssText =
					'position:fixed;pointer-events:none;z-index:7;' +
					'font-family:var(--font-mono);font-weight:700;' +
					'font-size:' + (big ? 13 : 10) + 'px;' +
					'color:var(--clay);opacity:0.75;' +
					'left:' + (rect.left + rect.width * 0.65 + rand(10)) + 'px;' +
					'top:' + (rect.top + 2) + 'px;' +
					'transition:transform 1.5s ease-out,opacity 1.5s ease-out;';
				document.body.appendChild(z);
				z.getBoundingClientRect();
				z.style.transform = 'translate(' + (rand(14) - 4) + 'px,-38px) rotate(' + (rand(22) - 11) + 'deg)';
				z.style.opacity   = '0';
				setTimeout(() => z.remove(), 1600);
				zCount++;
			}

			function clearZs() {
				clearInterval(zInterval);
				zInterval = null;
			}

			function spawnHeart() {
				const rect = el.getBoundingClientRect();
				const h    = document.createElement('span');
				h.textContent = '♥';
				h.style.cssText =
					'position:fixed;pointer-events:none;z-index:7;' +
					'font-family:var(--font-mono);font-weight:700;font-size:14px;' +
					'color:var(--phosphor);opacity:0.9;' +
					'left:' + (rect.left + rect.width * 0.5 + rand(12) - 6) + 'px;' +
					'top:' + (rect.top - 4) + 'px;' +
					'transition:transform 1.2s ease-out,opacity 1.2s ease-out;';
				document.body.appendChild(h);
				h.getBoundingClientRect();
				h.style.transform = 'translate(' + (rand(20) - 10) + 'px,-32px) scale(1.4)';
				h.style.opacity   = '0';
				setTimeout(() => h.remove(), 1300);
			}

			function goPet() {
				prevState = state;
				state     = 'petted';
				clearZs();
				set('pet');
				el.classList.remove('is-sleeping');
				el.classList.add('is-petted');
				spawnHeart();
				spawnHeart();
				bdToast(cfg.msgs[petCount % cfg.msgs.length]);
				petCount++;
				setTimeout(() => {
					el.classList.remove('is-petted');
					if (prevState === 'sleep') { goSleep(); }
					else { state = 'idle'; set('idle'); }
				}, 1200);
			}

			sprite.addEventListener('click', e => {
				e.stopPropagation();
				if (state !== 'petted') goPet();
			});

			function goSleep() {
				state = 'sleep';
				set('sleep');
				el.classList.add('is-sleeping');
				zCount    = 0;
				zInterval = setInterval(() => { if (state === 'sleep') spawnZ(); else clearZs(); }, 900);
			}

			function goWalk(scrollDir) {
				const mx   = maxX();
				const dist = 60 + rand(180);
				let tx     = x + scrollDir * dist;
				if (tx < 24 || tx > mx - 24) tx = scrollDir > 0 ? rand(mx / 2) : mx / 2 + rand(mx / 2);
				target = Math.max(8, Math.min(mx, tx));
				dir    = target > x ? 1 : -1;
				state  = 'walk';
				el.classList.toggle('is-flipped', dir < 0);
				el.classList.remove('is-sleeping');
				set('walkA');
			}

			window.addEventListener('scroll', () => {
				const sy        = window.scrollY;
				const scrollDir = sy > prevScrollY ? 1 : -1;
				prevScrollY     = sy;
				lastScrollTs    = performance.now();

				if (state === 'sleep') {
					clearZs();
					state = 'blink';
					set('blink');
					el.classList.remove('is-sleeping');
					setTimeout(() => { if (state === 'blink') goWalk(scrollDir); }, 350);
				} else if (state === 'idle') {
					goWalk(scrollDir);
				} else if (state === 'walk' && Math.abs(x - target) < 30 && Math.random() < 0.12) {
					goWalk(scrollDir);
				}
			}, { passive: true });

			function tick(ts) {
				if (lastTs === null) { lastTs = ts; requestAnimationFrame(tick); return; }
				const dt = Math.min((ts - lastTs) / 1000, 0.05);
				lastTs = ts;

				if (state !== 'sleep' && state !== 'blink' && state !== 'petted' && (ts - lastScrollTs) > SLEEP_AFTER) {
					if (state === 'walk') { state = 'idle'; set('idle'); }
					else if (state === 'idle' && (ts - lastScrollTs) > SLEEP_AFTER + 500) { goSleep(); }
				}

				if (state === 'walk') {
					x  += SPEED * dt * dir;
					x   = Math.max(8, Math.min(maxX(), x));
					el.style.left = x + 'px';

					if (ts - lastFlip > FRAME_MS) {
						frame ^= 1;
						set(frame ? 'walkB' : 'walkA');
						lastFlip = ts;
					}

					if (Math.abs(x - target) < 3 || x <= 8 || x >= maxX()) {
						state = 'idle';
						set('idle');
					}
				}

				requestAnimationFrame(tick);
			}

			goSleep();
			el.style.left = x + 'px';
			requestAnimationFrame(tick);
		}
	}

	/* ----------------------------------------------------- Console banner */

	function initConsoleBanner() {
		const css = 'font-family:monospace;color:#C96442;font-weight:bold;';
		console.log(
			'%c\n  ┌─────────────┐\n  │  Bd hello!  │\n  └─────────────┘\n  type "rosebud" :)\n',
			css
		);
	}

})();
